import SwiftUI

// A `Pin*` view's own description of how it renders, in design-token terms — generated by
// the `@Pinnable` macro from the component's declaration, so authors annotate instead of
// hand-writing the mapping. Design facts only (token names, radius, typography); any
// Figma/other mapping lives in the consumer.
public struct PinComponentStyle {
    public let name: String
    public let text: String?
    public let textStyle: PinTextStyle?
    public let textColorTokenName: String?
    public let fillTokenName: String?
    public let cornerRadius: CGFloat?
    public let centersText: Bool

    public init(
        name: String,
        text: String?,
        textStyle: PinTextStyle?,
        textColorTokenName: String?,
        fillTokenName: String?,
        cornerRadius: CGFloat?,
        centersText: Bool
    ) {
        self.name = name
        self.text = text
        self.textStyle = textStyle
        self.textColorTokenName = textColorTokenName
        self.fillTokenName = fillTokenName
        self.cornerRadius = cornerRadius
        self.centersText = centersText
    }
}

/// A token that names itself for capture, so the `name` mapping lives on the token once
/// rather than in every component. `@PinFill`/`@PinColor` read these.
public protocol PinFillToken {
    var captureFillToken: String? { get }
}

public protocol PinTextColorToken {
    var captureTextColorToken: String? { get }
}

public struct PinCapturedComponent {
    public let style: PinComponentStyle
    public let bounds: Anchor<CGRect>
    // Base64 PNG for rasterized nodes — native controls, images, SF Symbols — that have no
    // structured descriptor. `nil` for `@Pinnable` components, which rebuild from `style`.
    public let image: String?
    // A grouping node (e.g. a list row): the consumer nests other captured nodes whose frames fall
    // inside its bounds under it, so a row rebuilds as one Figma frame containing its labels.
    public let isContainer: Bool
    // A native/opaque bit (a switch, a chevron) the library can't describe structurally: the host
    // photographs its on-screen frame. The marker is pure SwiftUI — the host owns the screenshot —
    // so the library ships no window-capture code.
    public let needsRasterization: Bool
    // A stack layout the consumer can rebuild as a Figma auto-layout frame, so the imported design
    // reflows (a longer label, an added row) instead of being a fixed snapshot. Set on a container.
    public let layout: PinCaptureLayout?

    public init(
        style: PinComponentStyle, bounds: Anchor<CGRect>, image: String? = nil,
        isContainer: Bool = false, needsRasterization: Bool = false, layout: PinCaptureLayout? = nil
    ) {
        self.style = style
        self.bounds = bounds
        self.image = image
        self.isContainer = isContainer
        self.needsRasterization = needsRasterization
        self.layout = layout
    }
}

/// A stack's axis, spacing, and padding, captured so a container rebuilds as a Figma auto-layout
/// frame (`HStack` → row, `VStack` → column).
public struct PinCaptureLayout {
    public enum Axis { case row, column }
    public let axis: Axis
    public let spacing: CGFloat
    public let padding: EdgeInsets

    public init(axis: Axis, spacing: CGFloat, padding: EdgeInsets = EdgeInsets()) {
        self.axis = axis
        self.spacing = spacing
        self.padding = padding
    }
}

public struct PinCaptureKey: PreferenceKey {
    public static let defaultValue: [PinCapturedComponent] = []
    public nonisolated static func reduce(value: inout [PinCapturedComponent], nextValue: () -> [PinCapturedComponent]) {
        value.append(contentsOf: nextValue())
    }
}

public extension View {
    func pinCaptured(_ style: PinComponentStyle) -> some View {
        anchorPreference(key: PinCaptureKey.self, value: .bounds) { anchor in
            [PinCapturedComponent(style: style, bounds: anchor)]
        }
    }

    /// Marks this view as a capture group (e.g. a list row): captured nodes inside its bounds nest
    /// under it, so it rebuilds as one Figma frame containing its children. Uses
    /// `transformAnchorPreference` to *append* the container — plain `anchorPreference` would
    /// replace the descendants' captured nodes (the row's own labels) with just this one.
    func pinCapturedContainer(name: String, fillTokenName: String? = nil, cornerRadius: CGFloat? = nil, layout: PinCaptureLayout? = nil) -> some View {
        transformAnchorPreference(key: PinCaptureKey.self, value: .bounds) { value, anchor in
            value.append(PinCapturedComponent(
                style: PinComponentStyle(
                    name: name, text: nil, textStyle: nil, textColorTokenName: nil,
                    fillTokenName: fillTokenName, cornerRadius: cornerRadius, centersText: false
                ),
                bounds: anchor,
                isContainer: true,
                layout: layout
            ))
        }
    }

    /// Marks a native/opaque bit (a switch, a chevron) for the host to photograph — the library has
    /// no structured description of it. Emits only a marker; the host does the window-crop, so no
    /// screenshot code ships in the library. A no-op when nothing is capturing.
    func pinCapturedRasterized(name: String) -> some View {
        transformAnchorPreference(key: PinCaptureKey.self, value: .bounds) { value, anchor in
            value.append(PinCapturedComponent(
                style: PinComponentStyle(
                    name: name, text: nil, textStyle: nil, textColorTokenName: nil,
                    fillTokenName: nil, cornerRadius: nil, centersText: false
                ),
                bounds: anchor,
                needsRasterization: true
            ))
        }
    }
}
